payload.arguments:
{"cmd":"for base in /tmp /private/tmp /var/tmp /private/var/tmp; do
  echo "--- $base candidate list ---"
  [ -d "$base" ] || { echo "missing"; continue; }
  find "$base" -maxdepth 1 -mindepth 1 -type d -print0 2>/dev/null | xargs -0 -n1 -I{} sh -c 'n={};
    base=$(basename "$n");
    case "$base" in mac-*|mac_cleanup*|mac_48h*|codex*|eei*|adp*|playwright*|node-compile-cache|pytest-of-*|F3CNN|moomoo*|macos*|mac_cleanup*)
      s=$(du -sk "$n" 2>/dev/null | awk "{print \\$1}");
      m=$(stat -f "%Y" "$n" 2>/dev/null);
      if [ "${s:-0}" != "0" ]; then echo "$n\t$s KB"; fi;
      ;;
    esac'
  done
"}
